$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Introduceți numărul de zile pentru care statisticile brute ale vizitatorilor PrestaShop trebuie păstrate. Exemplu: 60 înseamnă că modulul păstrează ultimele 60 de zile și șterge înregistrările mai vechi din ps_connections, ps_connections_source și ps_connections_page. Nu setați 1 decât dacă sunteți sigur că nu aveți nevoie de statistici recente ale vizitatorilor.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Dimensiunea lotului';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Numărul maxim de conexiuni procesate într-un singur lot.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Introduceți câte înregistrări principale de conexiuni pot fi procesate într-un lot intern. Valorile mai mici sunt mai sigure pe hosting slab, dar necesită mai multe rulări cron. Valorile mai mari curăță mai repede, dar pot menține blocări ale bazei de date mai mult timp. Valoare inițială recomandată: 1000 până la 5000; creșteți doar după testarea timpului de rulare.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Număr maxim de loturi pe rulare';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Limitează cât lucru poate face o execuție cron.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Introduceți câte loturi pot rula în timpul unei execuții cron. Numărul total posibil de înregistrări principale șterse pe rulare este aproximativ Dimensiunea lotului înmulțită cu Număr maxim de loturi pe rulare. Exemplu: 5000 și 10 înseamnă până la aproximativ 50000 de înregistrări principale într-o rulare cron. Reduceți dacă magazinul încetinește în timpul curățării.';
