$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Agregă statisticile surselor de trafic înainte de ștergere';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Stochează statistici zilnice rezumate ale surselor de trafic înainte de a șterge rândurile brute.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Când este activat, modulul salvează un mic rezumat zilnic înainte de eliminarea statisticilor brute PrestaShop. Păstrează valori precum vizite, afișări de pagini, domeniul sursei și valori UTM. Nu stochează adrese IP, URL-uri referrer complete sau șiruri user-agent. Dezactivați dacă doriți doar ștergere și nu aveți nevoie de rezumate istorice ale surselor.';
