$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_bf45506cce2494894a9df6ff4bdf83ae'] = 'Agregă statisticile surselor de trafic înainte de ștergere';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_d7e1a0c7e7973ebcde37aa659525105d'] = 'Stochează statistici zilnice rezumate ale surselor de trafic înainte de a șterge rândurile brute.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ae729759e10d7a626a8622321932a1f4'] = 'Când este activat, modulul salvează un mic rezumat zilnic înainte de eliminarea statisticilor brute PrestaShop. Păstrează valori precum vizite, afișări de pagini, domeniul sursei și valori UTM. Nu stochează adrese IP, URL-uri referrer complete sau șiruri user-agent. Dezactivați dacă doriți doar ștergere și nu aveți nevoie de rezumate istorice ale surselor.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ce2b282d224153cccd645f28504ab4e2'] = 'Zile de păstrare pentru statistici agregate';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Cât timp trebuie păstrată tabela mică de rezumat zilnic.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Introduceți câte zile rezumatele agregate de trafic trebuie să rămână în tabela modulului. Exemplu: 730 păstrează aproximativ doi ani de rezumate zilnice ale surselor. Această setare afectează doar tabela ps_jooim_dbcleaner_traffic_daily, nu tabelele statistice originale PrestaShop.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Timeout pentru blocare veche în secunde';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Protecție împotriva rulării simultane a două procese de curățare.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Introduceți numărul de secunde după care o blocare de curățare neterminată este considerată abandonată. Aceasta protejează baza de date împotriva a două execuții cron simultane. Valoare recomandată: 7200. Reduceți doar dacă cronul este garantat că se termină rapid.';
